package com.ecommerce.search.service;

import com.ecommerce.search.dto.BulkIndexResponse;
import com.ecommerce.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.delete.DeleteResponse;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.action.update.UpdateResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class ProductIndexingService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    private static final String INDEX = IndexManagementService.PRODUCT_INDEX;

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null) {
            product.setId(UUID.randomUUID().toString());
        }
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(LocalDateTime.now());
        }
        product.setUpdatedAt(LocalDateTime.now());

        if (product.getInStock() == null) {
            product.setInStock(product.getStockQuantity() != null && product.getStockQuantity() > 0);
        }

        String jsonString = objectMapper.writeValueAsString(product);

        IndexRequest request = new IndexRequest(INDEX)
                .id(product.getId())
                .source(jsonString, XContentType.JSON);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        log.info("Product indexed: id={}, result={}", product.getId(), response.getResult());
        return product.getId();
    }

    public Product getProduct(String id) throws IOException {
        GetRequest request = new GetRequest(INDEX, id);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);

        if (response.isExists()) {
            Product product = objectMapper.readValue(response.getSourceAsString(), Product.class);
            product.setId(response.getId());
            return product;
        }
        return null;
    }

    public String updateProduct(String id, Product product) throws IOException {
        product.setUpdatedAt(LocalDateTime.now());
        String jsonString = objectMapper.writeValueAsString(product);

        UpdateRequest request = new UpdateRequest(INDEX, id)
                .doc(jsonString, XContentType.JSON)
                .docAsUpsert(true);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        log.info("Product updated: id={}, result={}", id, response.getResult());
        return id;
    }

    public Map<String, Object> partialUpdateProduct(String id, Map<String, Object> fields) throws IOException {
        fields.put("updatedAt", LocalDateTime.now().toString());

        UpdateRequest request = new UpdateRequest(INDEX, id)
                .doc(fields);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        log.info("Product partially updated: id={}, result={}", id, response.getResult());

        Map<String, Object> result = new HashMap<>();
        result.put("id", id);
        result.put("result", response.getResult().toString());
        return result;
    }

    public boolean deleteProduct(String id) throws IOException {
        DeleteRequest request = new DeleteRequest(INDEX, id);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);
        log.info("Product deleted: id={}, result={}", id, response.getResult());
        return response.getResult().toString().equals("DELETED");
    }

    public BulkIndexResponse bulkIndexProducts(List<Product> products) throws IOException {
        long startTime = System.currentTimeMillis();
        BulkRequest bulkRequest = new BulkRequest();
        List<String> errors = new ArrayList<>();

        for (Product product : products) {
            try {
                if (product.getId() == null) {
                    product.setId(UUID.randomUUID().toString());
                }
                if (product.getCreatedAt() == null) {
                    product.setCreatedAt(LocalDateTime.now());
                }
                product.setUpdatedAt(LocalDateTime.now());

                if (product.getInStock() == null) {
                    product.setInStock(product.getStockQuantity() != null && product.getStockQuantity() > 0);
                }

                String jsonString = objectMapper.writeValueAsString(product);
                IndexRequest indexRequest = new IndexRequest(INDEX)
                        .id(product.getId())
                        .source(jsonString, XContentType.JSON);
                bulkRequest.add(indexRequest);
            } catch (Exception e) {
                errors.add("Failed to prepare product " + product.getId() + ": " + e.getMessage());
            }
        }

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);

        int successCount = 0;
        int failureCount = 0;

        Arrays.stream(bulkResponse.getItems()).forEach(item -> {
            if (item.isFailed()) {
                errors.add("Failed to index " + item.getId() + ": " + item.getFailureMessage());
            }
        });

        successCount = (int) Arrays.stream(bulkResponse.getItems()).filter(item -> !item.isFailed()).count();
        failureCount = (int) Arrays.stream(bulkResponse.getItems()).filter(item -> item.isFailed()).count();

        long timeTaken = System.currentTimeMillis() - startTime;

        log.info("Bulk indexing completed: success={}, failures={}, time={}ms",
                successCount, failureCount, timeTaken);

        return BulkIndexResponse.builder()
                .totalProcessed(products.size())
                .successCount(successCount)
                .failureCount(failureCount)
                .errors(errors)
                .timeTakenMs(timeTaken)
                .build();
    }

    public BulkIndexResponse bulkDeleteProducts(List<String> ids) throws IOException {
        long startTime = System.currentTimeMillis();
        BulkRequest bulkRequest = new BulkRequest();
        List<String> errors = new ArrayList<>();

        for (String id : ids) {
            bulkRequest.add(new DeleteRequest(INDEX, id));
        }

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);

        int successCount = (int) Arrays.stream(bulkResponse.getItems())
                .filter(item -> !item.isFailed()).count();
        int failureCount = (int) Arrays.stream(bulkResponse.getItems())
                .filter(item -> item.isFailed()).count();

        Arrays.stream(bulkResponse.getItems())
                .filter(item -> item.isFailed())
                .forEach(item -> errors.add("Failed to delete " + item.getId() + ": " + item.getFailureMessage()));

        long timeTaken = System.currentTimeMillis() - startTime;

        return BulkIndexResponse.builder()
                .totalProcessed(ids.size())
                .successCount(successCount)
                .failureCount(failureCount)
                .errors(errors)
                .timeTakenMs(timeTaken)
                .build();
    }
}

