import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.histogram.Histogram;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.aggregations.metrics.Stats;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightField;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.suggest.SuggestBuilder;
import org.elasticsearch.search.suggest.SuggestBuilders;
import org.elasticsearch.search.suggest.completion.CompletionSuggestion;
import org.elasticsearch.search.suggest.phrase.PhraseSuggestion;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final SearchQueryService searchQueryService;

    private static final String INDEX = IndexManagementService.PRODUCT_INDEX;

    public ProductSearchResponse search(ProductSearchRequest searchRequest) throws IOException {
        long startTime = System.currentTimeMillis();

        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        // Build the main query
        BoolQueryBuilder boolQuery = buildMainQuery(searchRequest);

        // Apply function score for relevance boosting
        FunctionScoreQueryBuilder functionScoreQuery = buildFunctionScoreQuery(boolQuery);
        sourceBuilder.query(functionScoreQuery);

        // Add faceted aggregations
        addFacetAggregations(sourceBuilder);

        // Add highlighting
        addHighlighting(sourceBuilder);

        // Pagination
        sourceBuilder.from(searchRequest.getPage() * searchRequest.getSize());
        sourceBuilder.size(searchRequest.getSize());

        // Sorting
        applySorting(sourceBuilder, searchRequest);

        request.source(sourceBuilder);

        log.debug("Elasticsearch query: {}", sourceBuilder.toString());

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        long responseTime = System.currentTimeMillis() - startTime;

        ProductSearchResponse searchResponse = buildSearchResponse(response, searchRequest, responseTime);

        // Log search query asynchronously
        searchQueryService.logSearchQuery(searchRequest, searchResponse, responseTime);

        return searchResponse;
    }

    private BoolQueryBuilder buildMainQuery(ProductSearchRequest searchRequest) {
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search
        if (searchRequest.getQuery() != null && !searchRequest.getQuery().trim().isEmpty()) {
            String query = searchRequest.getQuery().trim();

            MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(query)
                    .field("name", 3.0f)
                    .field("name.keyword", 5.0f)
                    .field("description", 1.0f)
                    .field("brand", 2.0f)
                    .field("category", 2.0f)
                    .field("tags", 1.5f)
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness("AUTO")
                    .prefixLength(2)
                    .minimumShouldMatch("75%");

            boolQuery.must(multiMatch);

            // Boost exact phrase match
            boolQuery.should(QueryBuilders.matchPhraseQuery("name", query).boost(10.0f));
            boolQuery.should(QueryBuilders.matchPhraseQuery("description", query).boost(2.0f));
        }

        // Category filter
        if (searchRequest.getCategories() != null && !searchRequest.getCategories().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category.keyword", searchRequest.getCategories()));
        }

        // Brand filter
        if (searchRequest.getBrands() != null && !searchRequest.getBrands().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand.keyword", searchRequest.getBrands()));
        }

        // Color filter
        if (searchRequest.getColors() != null && !searchRequest.getColors().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("colors", searchRequest.getColors()));
        }

        // Size filter
        if (searchRequest.getSizes() != null && !searchRequest.getSizes().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("sizes", searchRequest.getSizes()));
        }

        // Tag filter
        if (searchRequest.getTags() != null && !searchRequest.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", searchRequest.getTags()));
        }

        // Price range filter
        if (searchRequest.getMinPrice() != null || searchRequest.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (searchRequest.getMinPrice() != null) {
                rangeQuery.gte(searchRequest.getMinPrice());
            }
            if (searchRequest.getMaxPrice() != null) {
                rangeQuery.lte(searchRequest.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        // Rating filter
        if (searchRequest.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(searchRequest.getMinRating()));
        }

        // In stock filter
        if (searchRequest.getInStock() != null && searchRequest.getInStock()) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", true));
        }

        // Featured filter
        if (searchRequest.getFeatured() != null && searchRequest.getFeatured()) {
            boolQuery.filter(QueryBuilders.termQuery("featured", true));
        }

        // Seller filter
        if (searchRequest.getSeller() != null && !searchRequest.getSeller().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("seller.keyword", searchRequest.getSeller()));
        }

        // Custom filters
        if (searchRequest.getCustomFilters() != null) {
            searchRequest.getCustomFilters().forEach((key, values) -> {
                boolQuery.filter(QueryBuilders.termsQuery("attributes." + key + ".keyword", values));
            });
        }

        return boolQuery;
    }

    private FunctionScoreQueryBuilder buildFunctionScoreQuery(BoolQueryBuilder boolQuery) {
        FunctionScoreQueryBuilder.FilterFunctionBuilder[] functions = new FunctionScoreQueryBuilder.FilterFunctionBuilder[]{
                // Boost products with higher ratings
                new FunctionScoreQueryBuilder.FilterFunctionBuilder(
                        ScoreFunctionBuilders.fieldValueFactorFunction("rating")
                                .factor(1.2f)
                                .modifier(org.elasticsearch.index.query.functionscore.FieldValueFactorFunction.Modifier.LOG1P)
                                .missing(1)
                ),
                // Boost products with more reviews
                new FunctionScoreQueryBuilder.FilterFunctionBuilder(
                        ScoreFunctionBuilders.fieldValueFactorFunction("reviewCount")
                                .factor(0.5f)
                                .modifier(org.elasticsearch.index.query.functionscore.FieldValueFactorFunction.Modifier.LOG1P)
                                .missing(0)
                ),
                // Boost featured products
                new FunctionScoreQueryBuilder.FilterFunctionBuilder(
                        QueryBuilders.termQuery("featured", true),
                        ScoreFunctionBuilders.weightFactorFunction(1.5f)
                ),
                // Boost in-stock products
                new FunctionScoreQueryBuilder.FilterFunctionBuilder(
                        QueryBuilders.termQuery("inStock", true),
                        ScoreFunctionBuilders.weightFactorFunction(1.3f)
                ),
                // Boost products with higher sales
                new FunctionScoreQueryBuilder.FilterFunctionBuilder(
                        ScoreFunctionBuilders.fieldValueFactorFunction("salesCount")
                                .factor(0.3f)
                                .modifier(org.elasticsearch.index.query.functionscore.FieldValueFactorFunction.Modifier.LOG1P)
                                .missing(0)
                ),
                // Recency boost
                new FunctionScoreQueryBuilder.FilterFunctionBuilder(
                        ScoreFunctionBuilders.exponentialDecayFunction("createdAt",
                                "now", "30d", "7d", 0.5)
                )
        };

        return QueryBuilders.functionScoreQuery(boolQuery, functions)
                .scoreMode(org.elasticsearch.common.lucene.search.function.FunctionScoreQuery.ScoreMode.SUM)
                .boostMode(org.elasticsearch.common.lucene.search.function.CombineFunction.MULTIPLY);
    }

    private void addFacetAggregations(SearchSourceBuilder sourceBuilder) {
        // Category facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("categories")
                        .field("category.keyword")
                        .size(50)
                        .order(org.elasticsearch.search.aggregations.BucketOrder.count(false))
        );

        // Brand facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("brands")
                        .field("brand.keyword")
                        .size(50)
                        .order(org.elasticsearch.search.aggregations.BucketOrder.count(false))
        );

        // Color facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("colors")
                        .field("colors")
                        .size(30)
        );

        // Size facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("sizes")
                        .field("sizes")
                        .size(30)
        );

        // Tag facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("tags")
                        .field("tags")
                        .size(50)
        );

        // Price range facet (histogram)
        sourceBuilder.aggregation(
                AggregationBuilders.histogram("price_ranges")
                        .field("price")
                        .interval(50)
                        .minDocCount(1)
        );

        // Price statistics
        sourceBuilder.aggregation(
                AggregationBuilders.stats("price_stats")
                        .field("price")
        );

        // Rating facet
        sourceBuilder.aggregation(
                AggregationBuilders.histogram("ratings")
                        .field("rating")
                        .interval(1)
                        .minDocCount(0)
        );

        // Seller facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("sellers")
                        .field("seller.keyword")
                        .size(30)
        );

        // In stock count
        sourceBuilder.aggregation(
                AggregationBuilders.terms("in_stock")
                        .field("inStock")
        );
    }

    private void addHighlighting(SearchSourceBuilder sourceBuilder) {
        HighlightBuilder highlightBuilder = new HighlightBuilder()
                .preTags("<em class=\"search-highlight\">")
                .postTags("</em>")
                .field(new HighlightBuilder.Field("name").numOfFragments(1))
                .field(new HighlightBuilder.Field("description").numOfFragments(2).fragmentSize(150))
                .field(new HighlightBuilder.Field("brand").numOfFragments(1));

        sourceBuilder.highlighter(highlightBuilder);
    }

    private void applySorting(SearchSourceBuilder sourceBuilder, ProductSearchRequest searchRequest) {
        String sortField = searchRequest.getSortField();
        SortOrder sortOrder = "asc".equalsIgnoreCase(searchRequest.getSortOrder())
                ? SortOrder.ASC : SortOrder.DESC;

        switch (sortField) {
            case "price":
                sourceBuilder.sort("price", sortOrder);
                break;
            case "rating":
                sourceBuilder.sort("rating", sortOrder);
                break;
            case "name":
                sourceBuilder.sort("name.keyword", sortOrder);
                break;
            case "createdAt":
            case "newest":
                sourceBuilder.sort("createdAt", SortOrder.DESC);
                break;
            case "salesCount":
            case "popularity":
                sourceBuilder.sort("salesCount", SortOrder.DESC);
                break;
            case "reviewCount":
                sourceBuilder.sort("reviewCount", SortOrder.DESC);
                break;
            case "discount":
                sourceBuilder.sort("discount", SortOrder.DESC);
                break;
            case "_score":
            default:
                // Default: relevance score
                break;
        }
    }

    private ProductSearchResponse buildSearchResponse(SearchResponse response,
                                                       ProductSearchRequest searchRequest,
                                                       long responseTime) throws IOException {
        List<Product> products = new ArrayList<>();

        for (SearchHit hit : response.getHits().getHits()) {
            Product product = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            product.setId(hit.getId());

            // Apply highlights if available
            Map<String, HighlightField> highlights = hit.getHighlightFields();
            if (highlights.containsKey("name")) {
                String highlightedName = Arrays.stream(highlights.get("name").getFragments())
                        .map(Text::string).collect(Collectors.joining(" "));
                // Store highlighted version (could use a separate field)
            }

            products.add(product);
        }

        long totalHits = response.getHits().getTotalHits().value;
        int totalPages = (int) Math.ceil((double) totalHits / searchRequest.getSize());

        // Extract facets
        Map<String, List<ProductSearchResponse.FacetBucket>> facets = extractFacets(response);

        return ProductSearchResponse.builder()
                .products(products)
                .totalHits(totalHits)
                .page(searchRequest.getPage())
                .size(searchRequest.getSize())
                .totalPages(totalPages)
                .responseTimeMs(responseTime)
                .facets(facets)
                .build();
    }

    private Map<String, List<ProductSearchResponse.FacetBucket>> extractFacets(SearchResponse response) {
        Map<String, List<ProductSearchResponse.FacetBucket>> facets = new LinkedHashMap<>();

        // Terms aggregations
        String[] termsAggNames = {"categories", "brands", "colors", "sizes", "tags", "sellers", "in_stock"};
        for (String aggName : termsAggNames) {
            Terms termsAgg = response.getAggregations().get(aggName);
            if (termsAgg != null) {
                List<ProductSearchResponse.FacetBucket> buckets = termsAgg.getBuckets().stream()
                        .map(bucket -> ProductSearchResponse.FacetBucket.builder()
                                .key(bucket.getKeyAsString())
                                .docCount(bucket.getDocCount())
                                .build())
                        .collect(Collectors.toList());
                facets.put(aggName, buckets);
            }
        }

        // Price ranges histogram
        Histogram priceRanges = response.getAggregations().get("price_ranges");
        if (priceRanges != null) {
            List<ProductSearchResponse.FacetBucket> priceBuckets = priceRanges.getBuckets().stream()
                    .map(bucket -> ProductSearchResponse.FacetBucket.builder()
                            .key(bucket.getKeyAsString())
                            .docCount(bucket.getDocCount())
                            .build())
                    .collect(Collectors.toList());
            facets.put("price_ranges", priceBuckets);
        }

        // Price statistics
        Stats priceStats = response.getAggregations().get("price_stats");
        if (priceStats != null) {
            List<ProductSearchResponse.FacetBucket> statsBuckets = new ArrayList<>();
            statsBuckets.add(ProductSearchResponse.FacetBucket.builder()
                    .key("min:" + priceStats.getMin()).docCount((long) priceStats.getMin()).build());
            statsBuckets.add(ProductSearchResponse.FacetBucket.builder()
                    .key("max:" + priceStats.getMax()).docCount((long) priceStats.getMax()).build());
            statsBuckets.add(ProductSearchResponse.FacetBucket.builder()
                    .key("avg:" + priceStats.getAvg()).docCount((long) priceStats.getAvg()).build());
            facets.put("price_stats", statsBuckets);
        }

        // Rating histogram
        Histogram ratings = response.getAggregations().get("ratings");
        if (ratings != null) {
            List<ProductSearchResponse.FacetBucket> ratingBuckets = ratings.getBuckets().stream()
                    .map(bucket -> ProductSearchResponse.FacetBucket.builder()
                            .key(bucket.getKeyAsString())
                            .docCount(bucket.getDocCount())
                            .build())
                    .collect(Collectors.toList());
            facets.put("ratings", ratingBuckets);
        }

        return facets;
    }

    public AutocompleteResponse autocomplete(String prefix, int maxSuggestions) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery()
                .should(QueryBuilders.matchQuery("name.autocomplete", prefix).boost(3.0f))
                .should(QueryBuilders.matchQuery("brand.autocomplete", prefix).boost(2.0f))
                .should(QueryBuilders.matchQuery("category.autocomplete", prefix).boost(2.0f))
                .should(QueryBuilders.prefixQuery("name.keyword", prefix).boost(5.0f))
                .minimumShouldMatch(1);

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(maxSuggestions);
        sourceBuilder.fetchSource(new String[]{"name", "brand", "category"}, null);

        // Add aggregations for brand and category suggestions
        sourceBuilder.aggregation(
                AggregationBuilders.terms("brand_suggestions")
                        .field("brand.keyword")
                        .size(5)
        );
        sourceBuilder.aggregation(
                AggregationBuilders.terms("category_suggestions")
                        .field("category.keyword")
                        .size(5)
        );

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        Set<String> seen = new HashSet<>();

        for (SearchHit hit : response.getHits().getHits()) {
            Map<String, Object> source = hit.getSourceAsMap();
            String name = (String) source.get("name");
            if (name != null && seen.add(name.toLowerCase())) {
                suggestions.add(name);
            }
        }

        List<String> brandSuggestions = new ArrayList<>();
        Terms brandTerms = response.getAggregations().get("brand_suggestions");
        if (brandTerms != null) {
            brandTerms.getBuckets().forEach(b -> brandSuggestions.add(b.getKeyAsString()));
        }

        List<String> categorySuggestions = new ArrayList<>();
        Terms categoryTerms = response.getAggregations().get("category_suggestions");
        if (categoryTerms != null) {
            categoryTerms.getBuckets().forEach(b -> categorySuggestions.add(b.getKeyAsString()));
        }

        return AutocompleteResponse.builder()
                .suggestions(suggestions)
                .brands(brandSuggestions)
                .categories(categorySuggestions)
                .build();
    }

    public List<Product> findSimilarProducts(String productId, int maxResults) throws IOException {
        Product product = getProductById(productId);
        if (product == null) {
            return Collections.emptyList();
        }

        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery()
                .mustNot(QueryBuilders.termQuery("id", productId));

        // Similar by category and brand
        if (product.getCategory() != null) {
            boolQuery.should(QueryBuilders.termQuery("category.keyword", product.getCategory()).boost(3.0f));
        }
        if (product.getBrand() != null) {
            boolQuery.should(QueryBuilders.termQuery("brand.keyword", product.getBrand()).boost(2.0f));
        }
        if (product.getTags() != null && !product.getTags().isEmpty()) {
            boolQuery.should(QueryBuilders.termsQuery("tags", product.getTags()).boost(1.5f));
        }

        // More like this
        boolQuery.should(QueryBuilders.moreLikeThisQuery(
                new String[]{"name", "description"},
                new String[]{product.getName() + " " + (product.getDescription() != null ? product.getDescription() : "")},
                null
        ).minTermFreq(1).minDocFreq(1).boost(2.0f));

        // Price range similarity (within 30% of current price)
        if (product.getPrice() != null) {
            double priceRange = product.getPrice().doubleValue() * 0.3;
            boolQuery.should(QueryBuilders.rangeQuery("price")
                    .gte(product.getPrice().doubleValue() - priceRange)
                    .lte(product.getPrice().doubleValue() + priceRange)
                    .boost(1.0f));
        }

        boolQuery.minimumShouldMatch(1);

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(maxResults);

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<Product> similarProducts = new ArrayList<>();
        for (SearchHit hit : response.getHits().getHits()) {
            Product p = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            p.setId(hit.getId());
            similarProducts.add(p);
        }

        return similarProducts;
    }

    private Product getProductById(String id) throws IOException {
        org.elasticsearch.action.get.GetRequest getRequest =
                new org.elasticsearch.action.get.GetRequest(INDEX, id);
        org.elasticsearch.action.get.GetResponse getResponse =
                client.get(getRequest, RequestOptions.DEFAULT);

        if (getResponse.isExists()) {
            Product product = objectMapper.readValue(getResponse.getSourceAsString(), Product.class);
            product.setId(getResponse.getId());
            return product;
        }
        return null;
    }
}

// src/main/java/com/ecommerce/search/service/SearchQueryService.java
package com.ecommerce.search.service;

import com.ecommerce.search.dto.ProductSearchRequest;
import com.ecommerce.search.dto.ProductSearchResponse;
import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class SearchQueryService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    private static final String INDEX = IndexManagementService.SEARCH_QUERY_INDEX;

    @Async
    public void logSearchQuery(ProductSearchRequest searchRequest,
                                ProductSearchResponse searchResponse,
                                long responseTimeMs) {
        try {
            SearchQuery searchQuery = SearchQuery.builder()
                    .id(UUID.randomUUID().toString())
                    .queryText(searchRequest.getQuery())
                    .userId(searchRequest.getUserId())
                    .sessionId(searchRequest.getSessionId())
                    .filters(buildFiltersMap(searchRequest))
                    .sortField(searchRequest.getSortField())
                    .sortOrder(searchRequest.getSortOrder())
                    .resultsCount((int) searchResponse.getTotalHits())
                    .responseTimeMs(responseTimeMs)
                    .timestamp(LocalDateTime.now())
                    .build();

            String jsonString = objectMapper.writeValueAsString(searchQuery);

            IndexRequest request = new IndexRequest(INDEX)
                    .id(searchQuery.getId())
                    .source(jsonString, XContentType.JSON);

            client.index(request, RequestOptions.DEFAULT);
            log.debug("Search query logged: {}", searchQuery.getQueryText());
        } catch (Exception e) {
            log.error("Failed to log search query", e);
        }
    }

    private Map<String, List<String>> buildFiltersMap(ProductSearchRequest request) {
        Map<String, List<String>> filters = new HashMap<>();

        if (request.getCategories() != null && !request.getCategories().isEmpty()) {
            filters.put("categories", request.getCategories());
        }
        if (request.getBrands() != null && !request.getBrands().isEmpty()) {
            filters.put("brands", request.getBrands());
        }
        if (request.getColors() != null && !request.getColors().isEmpty()) {
            filters.put("colors", request.getColors());
        }
        if (request.getSizes() != null && !request.getSizes().isEmpty()) {
            filters.put("sizes", request.getSizes());
        }
        if (request.getMinPrice() != null) {
            filters.put("minPrice", Collections.singletonList(request.getMinPrice().toString()));
        }
        if (request.getMaxPrice() != null) {
            filters.put("maxPrice", Collections.singletonList(request.getMaxPrice().toString()));
        }
        if (request.getMinRating() != null) {
            filters.put("minRating", Collections.singletonList(request.getMinRating().toString()));
        }

        return filters;
    }

    public void logProductClick(String searchQueryId, String productId) {
        try {
            Map<String, Object> params = new HashMap<>();
            params.put("script", "ctx._source.clickedProductIds.add(params.productId)");
            params.put("productId", productId);

            UpdateRequest updateRequest = new UpdateRequest(INDEX, searchQueryId)
                    .script(new org.elasticsearch.script.Script(
                            org.elasticsearch.script.ScriptType.INLINE,
                            "painless",
                            "if (ctx._source.clickedProductIds == null) { ctx._source.clickedProductIds = []; } ctx._source.clickedProductIds.add(params.productId)",
                            Collections.singletonMap("productId", productId)
                    ));

            client.update(updateRequest, RequestOptions.DEFAULT);
            log.debug("Product click logged: queryId={}, productId={}", searchQueryId, productId);
        } catch (Exception e) {
            log.error("Failed to log product click", e);
        }
    }

    public List<Map<String, Object>> getPopularSearchQueries(int size, int days) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte("now-" + days + "d"));

        sourceBuilder.aggregation(
                AggregationBuilders.terms("popular_queries")
                        .field("queryText.keyword")
                        .size(size)
                        .order(org.elasticsearch.search.aggregations.BucketOrder.count(false))
        );

        sourceBuilder.size(0);
        request.source(sourceBuilder);

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        Terms popularQueries = response.getAggregations().get("popular_queries");
        List<Map<String, Object>> results = new ArrayList<>();

        if (popularQueries != null) {
            popularQueries.getBuckets().forEach(bucket -> {
                Map<String, Object> entry = new HashMap<>();
                entry.put("query", bucket.getKeyAsString());
                entry.put("count", bucket.getDocCount());
                results.add(entry);
            });
        }

        return results;
    }

    public List<Map<String, Object>> getSearchAnalytics(int days) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte("now-" + days + "d"));

        // Zero-result searches
        sourceBuilder.aggregation(
                AggregationBuilders.filter("zero_results",
                        QueryBuilders.termQuery("resultsCount", 0))
        );

        // Average response time
        sourceBuilder.aggregation(
                AggregationBuilders.avg("avg_response_time")
                        .field("responseTimeMs")
        );

        // Searches per day
        sourceBuilder.aggregation(
                AggregationBuilders.dateHistogram("searches_per_day")
                        .field("timestamp")
                        .calendarInterval(org.elasticsearch.search.aggregations.bucket.histogram.DateHistogramInterval.DAY)
        );

        // Most used filters
        sourceBuilder.aggregation(
                AggregationBuilders.terms("sort_fields_used")
                        .field("sortField")
                        .size(10)
        );

        sourceBuilder.size(0);
        request.source(sourceBuilder);

        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<Map<String, Object>> analytics = new ArrayList<>();

        Map<String, Object> totalSearches = new HashMap<>();
        totalSearches.put("metric", "total_searches");
        totalSearches.put("value", response.getHits().getTotalHits().value);
        analytics.add(totalSearches);

        org.elasticsearch.search.aggregations.bucket.filter.Filter zeroResults =
                response.getAggregations().get("zero_results");
        if (zeroResults != null) {
            Map<String, Object> zeroResultMetric = new HashMap<>();
            zeroResultMetric.put("metric", "zero_result_searches");
            zeroResultMetric.put("value", zeroResults.getDocCount());
            analytics.add(zeroResultMetric);
        }

        org.elasticsearch.search.aggregations.metrics.Avg avgResponseTime =
                response.getAggregations().get("avg_response_time");
        if (avgResponseTime != null) {
            Map<String, Object> avgResponseMetric = new HashMap<>();
            avgResponseMetric.put("metric", "avg_response_time_ms");
            avgResponseMetric.put("value", avgResponseTime.getValue());
            analytics.add(avgResponseMetric);
        }

        return analytics;
    }

    public List<SearchQuery> getRecentSearches(String userId, int size) throws IOException {
        SearchRequest request = new SearchRequest(INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.termQuery("userId", userId));
        sourceBuilder.sort("timestamp", SortOrder.DESC);
        sourceBuilder.size(size);

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        List<SearchQuery> searches = new ArrayList<>();
        for (org.elasticsearch.search.SearchHit hit : response.getHits().getHits()) {
            SearchQuery searchQuery = objectMapper.readValue(hit.getSourceAsString(), SearchQuery.class);
            searchQuery.setId(hit.getId());
            searches.add(searchQuery);
        }

        return searches;
    }
}

